namespace BgControls.Windows.Input.Touch;/// <summary>/// 文档触控处理器管理器，负责协调和分发 UI 元素上的各类触控手势事件./// </summary>internal class DocumentTouchHandlerManager{    /// <summary>    /// 触控事件的呈现元素.    /// </summary>    private readonly UIElement presenter;    /// <summary>    /// 已注册的文档触控处理器列表.    /// </summary>    private readonly List<DocumentTouchHandler> touchHandlers;    /// <summary>    /// 上一次捕获到滑动手势的处理器，用于处理惯性事件.    /// </summary>    private DocumentTouchHandler? lastCapturedSwipeElement;    /// <summary>    /// 当前捕获到滑动手势的处理器.    /// </summary>    private DocumentTouchHandler? capturedSwipeElement;    /// <summary>    /// 当前捕获到捏合手势的处理器.    /// </summary>    private DocumentTouchHandler? capturedPinchElement;    /// <summary>    /// Initializes a new instance of the <see cref="DocumentTouchHandlerManager"/> class.    /// </summary>    /// <param name="presenter">触控事件的呈现元素.</param>    public DocumentTouchHandlerManager(UIElement presenter)    {        // 验证参数是否为空.        ArgumentNullException.ThrowIfNull(presenter, nameof(presenter));        this.presenter = presenter;        this.touchHandlers = new List<DocumentTouchHandler>();        // 自动附加触控事件监听.        this.AttachToTouchEvents();    }    /// <summary>    /// 向管理器中添加一个新的触控处理器.    /// </summary>    /// <param name="touchHandler">待添加的处理器实例.</param>    public void AddTouchHandler(DocumentTouchHandler touchHandler)    {        // 将处理器加入内部列表.        this.touchHandlers.Add(touchHandler);    }    /// <summary>    /// 附加触控手势事件到呈现元素.    /// </summary>    public void AttachToTouchEvents()    {        // 先解绑已有事件，防止重复订阅.        this.DetachFromTouchEvents();        // 订阅点击、滑动、捏合等各类路由手势事件.        TouchManager.AddTapEventHandler(this.presenter, this.OnTap);        TouchManager.AddTapHoldAndReleaseEventHandler(this.presenter, this.OnTapHoldAndRelease);        TouchManager.AddSwipeStartedEventHandler(this.presenter, this.OnSwipeStarted);        TouchManager.AddSwipeEventHandler(this.presenter, this.OnSwipe);        TouchManager.AddSwipeFinishedEventHandler(this.presenter, this.OnSwipeFinished);        TouchManager.AddSwipeInertiaStartedEventHandler(this.presenter, this.OnSwipeInertiaStarted);        TouchManager.AddSwipeInertiaEventHandler(this.presenter, this.OnSwipeInertia);        TouchManager.AddSwipeInertiaFinishedEventHandler(this.presenter, this.OnSwipeInertiaFinished);        TouchManager.AddPinchStartedEventHandler(this.presenter, this.OnPinchStart);        TouchManager.AddPinchEventHandler(this.presenter, this.OnPinch);        TouchManager.AddPinchFinishedEventHandler(this.presenter, this.OnPinchFinished);    }    /// <summary>    /// 从呈现元素上解除所有已附加的触控手势事件.    /// </summary>    public void DetachFromTouchEvents()    {        // 依次移除所有已订阅的处理器.        TouchManager.RemoveTapEventHandler(this.presenter, this.OnTap);        TouchManager.RemoveTapHoldAndReleaseEventHandler(this.presenter, this.OnTapHoldAndRelease);        TouchManager.RemoveSwipeStartedEventHandler(this.presenter, this.OnSwipeStarted);        TouchManager.RemoveSwipeEventHandler(this.presenter, this.OnSwipe);        TouchManager.RemoveSwipeFinishedEventHandler(this.presenter, this.OnSwipeFinished);        TouchManager.RemoveSwipeInertiaStartedEventHandler(this.presenter, this.OnSwipeInertiaStarted);        TouchManager.RemoveSwipeInertiaEventHandler(this.presenter, this.OnSwipeInertia);        TouchManager.RemoveSwipeInertiaFinishedEventHandler(this.presenter, this.OnSwipeInertiaFinished);        TouchManager.RemovePinchStartedEventHandler(this.presenter, this.OnPinchStart);        TouchManager.RemovePinchEventHandler(this.presenter, this.OnPinch);        TouchManager.RemovePinchFinishedEventHandler(this.presenter, this.OnPinchFinished);    }    /// <summary>    /// 处理捏合手势开始事件.    /// </summary>    private void OnPinchStart(object sender, PinchEventArgs e)    {        UIElement presentationSource = (UIElement)sender;        // 获取捏合时的两个触控点坐标.        Point[] touchPoints = new Point[2]        {            e.GetTouchPoint1(presentationSource).Position,            e.GetTouchPoint2(presentationSource).Position,        };        // 遍历处理器查找能够处理该区域捏合逻辑的对象.        foreach (DocumentTouchHandler handler in this.touchHandlers)        {            if (handler.CanPinch && handler.ShouldHandleTouch(touchPoints))            {                handler.PinchStarted(e);                this.capturedPinchElement = handler;                e.Handled = true;                break;            }        }    }    /// <summary>    /// 处理捏合手势进行中事件.    /// </summary>    private void OnPinch(object sender, PinchEventArgs e)    {        // 如果当前有被捕获的处理器，则将事件分发给它.        if (this.capturedPinchElement != null)        {            this.capturedPinchElement.Pinch(e);            e.Handled = true;        }    }    /// <summary>    /// 处理捏合手势完成事件.    /// </summary>    private void OnPinchFinished(object sender, PinchEventArgs e)    {        if (this.capturedPinchElement != null)        {            this.capturedPinchElement.PinchFinished(e);            this.capturedPinchElement = null;            e.Handled = true;        }    }    /// <summary>    /// 处理点击手势事件.    /// </summary>    private void OnTap(object sender, TapEventArgs e)    {        // 获取点击的具体坐标.        Point tapLocation = e.GetTouchPoint((UIElement)sender).Position;        foreach (DocumentTouchHandler handler in this.touchHandlers)        {            if (handler.CanTap && handler.ShouldHandleTouch(tapLocation))            {                handler.Tap(e);                e.Handled = true;                break;            }        }    }    /// <summary>    /// 处理点击按住并释放手势事件.    /// </summary>    private void OnTapHoldAndRelease(object sender, TouchEventArgs e)    {        Point holdLocation = e.GetTouchPoint((UIElement)sender).Position;        foreach (DocumentTouchHandler handler in this.touchHandlers)        {            if (handler.CanTap && handler.ShouldHandleTouch(holdLocation))            {                handler.TapHoldAndRelease(e);                break;            }        }    }    /// <summary>    /// 处理滑动手势开始事件.    /// </summary>    private void OnSwipeStarted(object sender, TouchEventArgs e)    {        Point swipeStartLocation = e.GetTouchPoint((UIElement)sender).Position;        foreach (DocumentTouchHandler handler in this.touchHandlers)        {            if (handler.CanSwipe && handler.ShouldHandleTouch(swipeStartLocation))            {                handler.SwipeStarted(e);                this.capturedSwipeElement = handler;                e.Handled = true;                break;            }        }    }    /// <summary>    /// 处理滑动手势进行中事件.    /// </summary>    private void OnSwipe(object sender, SwipeEventArgs e)    {        if (this.capturedSwipeElement != null)        {            this.capturedSwipeElement.Swipe(e);            e.Handled = true;        }    }    /// <summary>    /// 处理滑动惯性开始事件.    /// </summary>    private void OnSwipeInertiaStarted(object sender, RoutedEventArgs e)    {        // 使用上一个捕获的元素来处理惯性逻辑.        if (this.lastCapturedSwipeElement != null)        {            this.lastCapturedSwipeElement.SwipeInertiaStarted(e);            e.Handled = true;        }    }    /// <summary>    /// 处理滑动惯性进行中事件.    /// </summary>    private void OnSwipeInertia(object sender, SwipeInertiaEventArgs e)    {        if (this.lastCapturedSwipeElement != null)        {            this.lastCapturedSwipeElement.SwipeInertia(e);            e.Handled = true;        }    }    /// <summary>    /// 处理滑动惯性结束事件.    /// </summary>    private void OnSwipeInertiaFinished(object sender, RoutedEventArgs e)    {        if (this.lastCapturedSwipeElement != null)        {            this.lastCapturedSwipeElement.SwipeInertiaFinished(e);            e.Handled = true;        }    }    /// <summary>    /// 处理滑动手势完成事件.    /// </summary>    private void OnSwipeFinished(object sender, TouchEventArgs e)    {        if (this.capturedSwipeElement != null)        {            this.capturedSwipeElement.SwipeFinished(e);            // 记录下该元素，以便后续触发惯性事件.            this.lastCapturedSwipeElement = this.capturedSwipeElement;            this.capturedSwipeElement = null;            e.Handled = true;        }    }}